SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY created_at DESC) AS RNUM, qna_id, title, writer_name, is_secret, status, TO_CHAR(created_at, 'yyyy-mm-dd') AS created_at FROM QUESTIONS WHERE fk_hotel_id = #{hotelId}
AND (title LIKE '%'||#{searchKeyword}||'%' OR content LIKE '%'||#{searchKeyword}||'%')
) V WHERE RNUM BETWEEN #{startRno} AND #{endRno}
